// ===== man-cart.js =====
// Lógica compartida del carrito de compras del prototipo Industrias MAN.
// Fuente única de verdad para: catálogo de productos, lectura/escritura del carrito
// (localStorage), badge del header y confirmación de pedido.
// Incluir con <script src="man-cart.js"></script> ANTES de cualquier script de la
// página que use estas funciones (ej. antes del script que renderiza el checkout).

const MAN_PRODUCT_CATALOG = {
  "freal2020": { name:"Circulador Freal 2020 MAN", sku:"CF02020PGR141", price:1573.00, href:"pdp-circulador-freal-2020.html", img:"data:image/jpeg;base64," },
  "lmv9090": { name:"Licuadora LMV-9090 MAN", sku:"LMV9090PGR092", price:1160.00, href:"pdp-licuadora-lmv-9090.html", img:"data:image/jpeg;base64," },
  "op3007": { name:"Olla de Presión OP-3007 MAN", sku:"OP3007ACI078", price:2662.55, href:"pdp-olla-op-3007.html", img:"data:image/jpeg;base64," },
  "aspa18": { name:"Aspa Ventilador 18\" MAN", sku:"ASP18REF033", price:86.00, href:"pdp-aspa-ventilador-18.html", img:"data:image/jpeg;base64," }
};

function manFmt(n){ return '$' + n.toLocaleString('es-MX', {minimumFractionDigits:2, maximumFractionDigits:2}); }

function manGetCart(){
  try { return JSON.parse(localStorage.getItem('man_cart')) || []; } catch(e){ return []; }
}

function manSaveCart(cart){
  localStorage.setItem('man_cart', JSON.stringify(cart));
  manUpdateCartBadge();
}

function manAddToCart(sku, qty){
  qty = qty || 1;
  var cart = manGetCart();
  var existing = cart.find(function(i){ return i.sku === sku; });
  if(existing){ existing.qty += qty; } else { cart.push({sku:sku, qty:qty}); }
  manSaveCart(cart);
}

function manCartLines(){
  return manGetCart().map(function(i){
    var p = MAN_PRODUCT_CATALOG[i.sku];
    if(!p) return null;
    return { sku:i.sku, qty:i.qty, name:p.name, price:p.price, img:p.img, href:p.href, sku_label:p.sku, subtotal: p.price * i.qty };
  }).filter(Boolean);
}

// Piezas totales en el carrito (suma de cantidades, no de productos distintos).
function manCartCount(){
  return manGetCart().reduce(function(sum, i){ return sum + (i.qty || 0); }, 0);
}

// Actualiza todos los badges de carrito presentes en la página actual (header).
function manUpdateCartBadge(){
  var count = manCartCount();
  document.querySelectorAll('.cart-badge').forEach(function(el){
    el.textContent = count;
  });
}

function manClearCart(){
  localStorage.removeItem('man_cart');
  manUpdateCartBadge();
}

// Se llama al confirmar el pedido en checkout.html: congela el resumen del
// pedido (productos + total) en 'man_last_order' para que confirmacion.html
// lo pueda mostrar, y vacía el carrito (simulando una compra real).
function manConfirmOrder(){
  var lines = manCartLines();
  var subtotal = lines.reduce(function(sum, l){ return sum + l.subtotal; }, 0);
  var order = {
    number: 'MAN-' + Math.floor(10000 + Math.random() * 89999),
    date: new Date().toLocaleDateString('es-MX', { day:'numeric', month:'long', year:'numeric' }),
    total: subtotal,
    items: lines.map(function(l){ return { name:l.name, qty:l.qty, subtotal:l.subtotal, img:l.img }; })
  };
  localStorage.setItem('man_last_order', JSON.stringify(order));
  manClearCart();
  return order;
}

document.addEventListener('DOMContentLoaded', manUpdateCartBadge);
